 1→import type { AuthorityAction } from "../iam/authority";
 2→import { jsonError } from "../http/response";
 3→import { BRAIN_SCOPES } from "../../shared/scopes";
 4→
 5→export { BRAIN_SCOPES };
 6→
 7→export type BrainScope = keyof typeof BRAIN_SCOPES;
 8→
 9→/** Map each authority action to the OAuth scope that gates it */
10→export const ACTION_SCOPE_MAP: Record<AuthorityAction, BrainScope> = {
11→  create_decision: "decision:write",
12→  confirm_decision: "decision:write",
13→  create_task: "task:write",
14→  complete_task: "task:write",
15→  create_observation: "observation:write",
16→  acknowledge_observation: "observation:write",
17→  resolve_observation: "observation:write",
18→  create_question: "question:write",
19→  create_suggestion: "task:write",
20→};
21→
22→/** All scopes requested by default during brain init */
23→export const DEFAULT_CLI_SCOPES = Object.keys(BRAIN_SCOPES).join(" ");
24→
25→/** Returns 403 Response if the token lacks the required scope, undefined otherwise */
26→export function requireScope(scopes: Set<string>, required: BrainScope): Response | undefined {
27→  if (!scopes.has(required)) {
28→    return jsonError(`insufficient scope: requires ${required}`, 403);
29→  }
30→  return undefined;
31→}
