631→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
632→  LET $query = string::lowercase(string::trim($q));
633→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
634→
635→  LET $task_rows = SELECT
636→    id,
637→    "task" AS kind,
638→    title AS text,
639→    extraction_confidence AS confidence,
640→    source_message AS sourceMessage,
641→    priority,
642→    created_at
643→  FROM task
644→  WHERE workspace = $workspace
645→    AND extraction_confidence != NONE
646→    AND string::contains(string::lowercase(title), $query)
647→  ORDER BY created_at DESC
648→  LIMIT $safe_limit;
649→
650→  LET $decision_rows = SELECT
651→    id,
652→    "decision" AS kind,
653→    summary AS text,
654→    extraction_confidence AS confidence,
655→    source_message AS sourceMessage,
656→    priority,
657→    created_at
658→  FROM decision
659→  WHERE workspace = $workspace
660→    AND extraction_confidence != NONE
661→    AND string::contains(string::lowercase(summary), $query)
662→  ORDER BY created_at DESC
663→  LIMIT $safe_limit;
664→
665→  LET $question_rows = SELECT
666→    id,
667→    "question" AS kind,
668→    text AS text,
669→    extraction_confidence AS confidence,
670→    source_message AS sourceMessage,
671→    priority,
672→    created_at
673→  FROM question
674→  WHERE workspace = $workspace
675→    AND extraction_confidence != NONE
676→    AND string::contains(string::lowercase(text), $query)
677→  ORDER BY created_at DESC
678→  LIMIT $safe_limit;
679→
680→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
681→};
