779→DEFINE FUNCTION fn::workspace_entity_ids($ws: record<workspace>) {
780→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
781→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
782→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
783→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
784→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
785→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
786→  LET $provenance = (
787→    SELECT VALUE out FROM extraction_relation
788→    WHERE `in` IN (
789→      SELECT VALUE id FROM message
790→      WHERE conversation IN (
791→        SELECT VALUE id FROM conversation WHERE workspace = $ws
792→      )
793→    )
794→  );
795→  RETURN array::distinct(
796→    $projects + $features + $tasks +
797→    $belongs_project + $belongs_feature +
798→    $identities + $provenance
799→  );

